// Classify each appointment based on timing and status
const items = $input.all();
const now = new Date();

const results = {
  send_24h_reminder: [],
  send_2h_reminder: [],
  check_noshow: [],
  send_survey: []
};

for (const item of items) {
  const row = item.json;
  const status = (row.Status || '').trim().toLowerCase();

  // Skip cancelled or already-processed
  if (['cancelled', 'canceled', 'no-show processed'].includes(status)) continue;

  // Parse appointment datetime
  let apptDateTime;
  try {
    // Try combining Date + Time columns
    const dateStr = row.Date || '';
    const timeStr = row.Time || '09:00';
    apptDateTime = new Date(`${dateStr} ${timeStr}`);
    if (isNaN(apptDateTime)) throw new Error('Invalid date');
  } catch {
    continue; // Skip rows with invalid dates
  }

  const msUntilAppt = apptDateTime - now;
  const hoursUntilAppt = msUntilAppt / (1000 * 60 * 60);
  const msSinceAppt = now - apptDateTime;
  const minutesSinceAppt = msSinceAppt / (1000 * 60);

  const common = {
    name: row.Name,
    email: row.Email,
    phone: row.Phone,
    date: row.Date,
    time: row.Time,
    status: row.Status,
    reminder_24h_sent: row.Reminder_24h_Sent,
    reminder_2h_sent: row.Reminder_2h_Sent,
    survey_sent: row.Survey_Sent,
    _appt_datetime: apptDateTime.toISOString()
  };

  // 24h reminder: 23-25 hours before, not yet sent
  if (hoursUntilAppt >= 23 && hoursUntilAppt <= 25 && row.Reminder_24h_Sent !== 'Yes') {
    results.send_24h_reminder.push({ json: common });
  }

  // 2h reminder: 1.75-2.25 hours before, not yet sent
  if (hoursUntilAppt >= 1.75 && hoursUntilAppt <= 2.25 && row.Reminder_2h_Sent !== 'Yes') {
    results.send_2h_reminder.push({ json: common });
  }

  // No-show check: 30-90 minutes after appointment, status still not 'Attended'
  if (minutesSinceAppt >= 30 && minutesSinceAppt <= 90 && 
      status !== 'attended' && row.Reminder_24h_Sent === 'Yes') {
    results.check_noshow.push({ json: common });
  }

  // Survey: 2-3 hours after appointment, status is 'Attended', survey not sent
  if (minutesSinceAppt >= 120 && minutesSinceAppt <= 180 && 
      status === 'attended' && row.Survey_Sent !== 'Yes') {
    results.send_survey.push({ json: common });
  }
}

// Return all appointments that need action, tagged with action type
const allActions = [
  ...results.send_24h_reminder.map(i => ({ json: { ...i.json, _action: '24h_reminder' } })),
  ...results.send_2h_reminder.map(i => ({ json: { ...i.json, _action: '2h_reminder' } })),
  ...results.check_noshow.map(i => ({ json: { ...i.json, _action: 'noshow' } })),
  ...results.send_survey.map(i => ({ json: { ...i.json, _action: 'survey' } }))
];

console.log(`Actions needed: 24h=${results.send_24h_reminder.length}, 2h=${results.send_2h_reminder.length}, noshow=${results.check_noshow.length}, survey=${results.send_survey.length}`);

return allActions.length > 0 ? allActions : [{ json: { _action: 'none', message: 'No appointments need action right now.' } }];

// Calculate no-show rate and write to stats sheet
const items = $input.all();
const today = new Date().toDateString();

const todayAppts = items.filter(i => {
  try { return new Date(i.json.Date).toDateString() === today; } catch { return false; }
});

const attended = todayAppts.filter(i => (i.json.Status || '').toLowerCase() === 'attended').length;
const noShow = todayAppts.filter(i => (i.json.Status || '').toLowerCase() === 'no-show').length;
const total = todayAppts.length;
const noShowRate = total > 0 ? ((noShow / total) * 100).toFixed(1) : '0.0';

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    total_appointments: total,
    attended: attended,
    no_shows: noShow,
    no_show_rate_pct: parseFloat(noShowRate),
    recorded_at: new Date().toISOString()
  }
}];

const error = $input.first().json;
console.error('ME-11 Error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Reminder system error', timestamp: new Date().toISOString() } }];
